import{_ as t,a,b as d,c as n}from"./chunks/授权后复制刷新令牌.DFAJxpN4.js";import{_ as o,o as s,c as i,a2 as l}from"./chunks/framework.DnrXFDHb.js";const g=JSON.parse('{"title":"Yandex 渠道添加说明","description":"","frontmatter":{},"headers":[],"relativePath":"cn/upload/yandex.md","filePath":"cn/upload/yandex.md","lastUpdated":1781962217000}'),r={name:"cn/upload/yandex.md"};function c(h,e,p,x,b,u){return s(),i("div",null,[...e[0]||(e[0]=[l('<h1 id="yandex-渠道添加说明" tabindex="-1">Yandex 渠道添加说明 <a class="header-anchor" href="#yandex-渠道添加说明" aria-label="Permalink to &quot;Yandex 渠道添加说明&quot;">​</a></h1><h2 id="添加前要准备什么" tabindex="-1">添加前要准备什么 <a class="header-anchor" href="#添加前要准备什么" aria-label="Permalink to &quot;添加前要准备什么&quot;">​</a></h2><table tabindex="0"><thead><tr><th>需要准备</th><th>用途</th></tr></thead><tbody><tr><td>一个 Yandex 账号</td><td>用来登录 Yandex 并授权 Yandex Disk</td></tr><tr><td>一个 Yandex OAuth 应用</td><td>用来生成 <code>Client ID</code> 和 <code>Client Secret</code></td></tr><tr><td>当前图床访问域名</td><td>用来配置授权回调地址</td></tr><tr><td>一个可用的 Yandex Disk</td><td>后面真正存图用</td></tr></tbody></table><h2 id="添加步骤" tabindex="-1">添加步骤 <a class="header-anchor" href="#添加步骤" aria-label="Permalink to &quot;添加步骤&quot;">​</a></h2><h3 id="第一步-创建-yandex-oauth-应用" tabindex="-1">第一步：创建 Yandex OAuth 应用 <a class="header-anchor" href="#第一步-创建-yandex-oauth-应用" aria-label="Permalink to &quot;第一步：创建 Yandex OAuth 应用&quot;">​</a></h3><ol><li>打开 Yandex OAuth 创建应用直达地址：</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://oauth.yandex.com/client/new</span></span></code></pre></div><ol start="2"><li>如果页面先跳到登录页，先登录你的 Yandex 账号。</li><li>创建一个新应用。</li><li>给应用起一个你自己能认出来的名字，例如 <code>imgbed-yandex</code>。</li><li>在应用设置里找到回调地址相关配置。</li><li>回调地址填：</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://你的域名/api/oauth/yandex/callback</span></span></code></pre></div><h3 id="第二步-确认授权范围" tabindex="-1">第二步：确认授权范围 <a class="header-anchor" href="#第二步-确认授权范围" aria-label="Permalink to &quot;第二步：确认授权范围&quot;">​</a></h3><p>按当前项目真实逻辑，Yandex 这条线建议保留 <code>Yandex.Disk REST API</code> 下这 4 个权限：</p><table tabindex="0"><thead><tr><th>权限</th><th>作用</th></tr></thead><tbody><tr><td><code>cloud_api:disk.app_folder</code></td><td>让系统把文件存到应用目录</td></tr><tr><td><code>cloud_api:disk.read</code></td><td>读取文件和下载链接</td></tr><tr><td><code>cloud_api:disk.write</code></td><td>上传文件、建目录、删文件</td></tr><tr><td><code>Access to information about Yandex.Disk</code></td><td>读取磁盘容量、已用空间等信息</td></tr></tbody></table><p>如果你还看到 <code>Yandex ID API</code> 下面的用户名、邮箱权限：</p><table tabindex="0"><thead><tr><th>页面上的权限文案</th><th>建议</th></tr></thead><tbody><tr><td><code>Access to username, first name and surname, gender</code></td><td>可选</td></tr><tr><td><code>Access to email address</code></td><td>可选</td></tr></tbody></table><p>当前项目核心上传、下载、删图、查容量，主要依赖的是上面那 4 个 <code>Yandex.Disk REST API</code> 权限。</p><p><img src="'+t+'" alt="配置 Yandex Disk 权限" loading="lazy"></p><h3 id="第三步-记录应用信息" tabindex="-1">第三步：记录应用信息 <a class="header-anchor" href="#第三步-记录应用信息" aria-label="Permalink to &quot;第三步：记录应用信息&quot;">​</a></h3><p>应用创建完成后，记下这两个值：</p><table tabindex="0"><thead><tr><th>Yandex 后台字段</th><th>后面填到哪里</th></tr></thead><tbody><tr><td><code>Client ID</code></td><td>系统里的 <code>Client ID</code></td></tr><tr><td><code>Client Secret</code></td><td>系统里的 <code>Client Secret</code></td></tr></tbody></table><p><img src="'+a+'" alt="记录客户端 ID 和 Secret" loading="lazy"></p><h3 id="第四步-回系统里填写-yandex-渠道" tabindex="-1">第四步：回系统里填写 Yandex 渠道 <a class="header-anchor" href="#第四步-回系统里填写-yandex-渠道" aria-label="Permalink to &quot;第四步：回系统里填写 Yandex 渠道&quot;">​</a></h3><p>在上传设置里选择 <code>Yandex</code> 后，按下面这套填：</p><table tabindex="0"><thead><tr><th>页面字段</th><th>你该填什么</th></tr></thead><tbody><tr><td>渠道名称</td><td>你自己起，例如 <code>Yandex主账号</code></td></tr><tr><td>Client ID</td><td>刚才 Yandex 应用的 <code>Client ID</code></td></tr><tr><td>Client Secret</td><td>刚才 Yandex 应用的 <code>Client Secret</code></td></tr><tr><td>Refresh Token</td><td>先留空</td></tr><tr><td>根目录</td><td>可选，默认 <code>imgbed</code></td></tr></tbody></table><p><img src="'+d+'" alt="编辑配置渠道" loading="lazy"></p><h3 id="第五步-获取-refresh-token" tabindex="-1">第五步：获取 Refresh Token <a class="header-anchor" href="#第五步-获取-refresh-token" aria-label="Permalink to &quot;第五步：获取 Refresh Token&quot;">​</a></h3><ol><li>在系统里点 <code>获取令牌</code>。</li><li>登录你要绑定的 Yandex 账号。</li><li>按提示授权。</li><li>授权成功后，回调页会显示一串 <code>Refresh Token</code>。</li><li>复制它。</li><li>回到系统，粘贴到 <code>Refresh Token</code> 输入框里。</li></ol><p><img src="'+n+`" alt="授权后复制刷新令牌" loading="lazy"></p><h3 id="第六步-保存渠道配置" tabindex="-1">第六步：保存渠道配置 <a class="header-anchor" href="#第六步-保存渠道配置" aria-label="Permalink to &quot;第六步：保存渠道配置&quot;">​</a></h3><p>字段填好后直接点击保存。</p><h2 id="渠道流程速查" tabindex="-1">渠道流程速查 <a class="header-anchor" href="#渠道流程速查" aria-label="Permalink to &quot;渠道流程速查&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>打开 Yandex OAuth 控制台</span></span>
<span class="line"><span>-&gt; 创建应用</span></span>
<span class="line"><span>-&gt; 配置回调地址 https://你的域名/api/oauth/yandex/callback</span></span>
<span class="line"><span>-&gt; 确认 Disk 权限</span></span>
<span class="line"><span>-&gt; 复制 Client ID 和 Client Secret</span></span>
<span class="line"><span>-&gt; 回系统填 Client ID / Client Secret</span></span>
<span class="line"><span>-&gt; 点击 获取令牌</span></span>
<span class="line"><span>-&gt; 复制回调页里的 Refresh Token</span></span>
<span class="line"><span>-&gt; 粘回系统保存</span></span></code></pre></div><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><ol><li>Yandex 注册应用：<a href="https://yandex.com/dev/id/doc/en/register-client" target="_blank" rel="noreferrer">https://yandex.com/dev/id/doc/en/register-client</a></li><li>Yandex 通过 URL 获取授权码：<a href="https://yandex.com/dev/id/doc/en/codes/code-url" target="_blank" rel="noreferrer">https://yandex.com/dev/id/doc/en/codes/code-url</a></li><li>Yandex OAuth 令牌接口：<a href="https://yandex.com/dev/id/doc/en/tokens/token" target="_blank" rel="noreferrer">https://yandex.com/dev/id/doc/en/tokens/token</a></li></ol>`,33)])])}const y=o(r,[["render",c]]);export{g as __pageData,y as default};
